def _transcribe_chunk(self, audio_path: str) -> str:
    with open(audio_path, "rb") as f:
        response = self.client.audio.transcriptions.create(
            model="whisper-1", file=f
        )
    return response.text  # NOT: return response

import tempfile
from pathlib import Path
from pydub import AudioSegment

class LongAudioTranscriber:
    def __init__(self, chunk_duration_ms: int = 300000, overlap_ms: int = 3000):
        self.chunk_duration = chunk_duration_ms
        self.overlap = overlap_ms

    def transcribe(self, audio_path: str) -> dict:
        audio = AudioSegment.from_file(audio_path)
        if len(audio) <= self.chunk_duration:
            return {"text": self._transcribe_chunk(audio_path)}
        return self._merge_results(self._process_chunks(audio))

    def _process_chunks(self, audio: AudioSegment) -> list:
        results = []
        start = 0
        tmpdir = tempfile.mkdtemp()  # unique dir per call — safe for concurrent agents
        while start < len(audio):
            end = min(start + self.chunk_duration, len(audio))
            chunk_path = str(Path(tmpdir) / f"chunk_{start}.mp3")
            audio[start:end].export(chunk_path, format="mp3")
            results.append({"start": start, "end": end, "text": self._transcribe_chunk(chunk_path)})
            Path(chunk_path).unlink()
            start = end - self.overlap
        return results

import torch
from pyannote.audio import Pipeline

pipeline = Pipeline.from_pretrained(
    "pyannote/speaker-diarization-3.1",
    use_auth_token=hf_token  # requires model license accepted at hf.co
)
if torch.cuda.is_available():
    pipeline.to(torch.device("cuda"))
else:
    raise RuntimeError("GPU required for production diarization")

from pathlib import Path

def route_transcription(path: str) -> str:
    size_mb = Path(path).stat().st_size / (1024 * 1024)
    if size_mb > 25:
        return "chunked"
    elif size_mb > 5:
        return "standard"
    return "direct"
